'use client';
import React, { useState, useEffect, createContext, useContext, ReactNode } from 'react';

interface FontContextType {
  selectedFont: string;
  setSelectedFont: (font: string) => void;
}

const FontContext = createContext<FontContextType | undefined>(undefined);

export const FontProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [selectedFont, setSelectedFont] = useState<string>('hin115');
  return (
    <FontContext.Provider value={{ selectedFont, setSelectedFont }}>
      {children}
    </FontContext.Provider>
  );
};

export const useFont = (): FontContextType => {
  const context = useContext(FontContext);
  if (!context) {
    throw new Error('useFont must be used within a FontProvider');
  }
  return context;
};

const FontPicker: React.FC = () => {
  const { selectedFont, setSelectedFont } = useFont();
  const fonts: string[] = ['hin115', 'ing115'];

  return (
    <select value={selectedFont} onChange={(e) => setSelectedFont(e.target.value)}>
      {fonts.map((font) => (
        <option key={font} value={font}>
          {font}
        </option>
      ))}
    </select>
  );
};
export default FontPicker;
